const input = $input.first().json;

const contextMap = {
  daily:     { table: 'journal_entries',       query: 'match_journal_entries' },
  weekly:    { table: 'journal_entries',       query: 'match_journal_entries' },
  monthly:   { table: 'weekly_condensations',  query: 'match_weekly_condensations' },
  yearly:    { table: 'monthly_condensations', query: 'match_monthly_condensations' },
  inception: { table: 'yearly_condensations',  query: 'match_yearly_condensations' }
};

const mapping = contextMap[input.context_type] || contextMap['daily'];

return [{
  json: {
    user_id: input.user_id,
    context_type: input.context_type,
    query_text: input.query_text,
    table_name: mapping.table,
    query_name: mapping.query
  }
}];

const items = $input.all();
const results = items.map(item => ({
  text: item.json.pageContent || '',
  metadata: item.json.metadata || {}
}));
return [{ json: { search_results: results } }];

const searchResults = $('Collect Search Results').first().json.search_results || [];
const ampItems = $input.all();

// Tylko aktywne rekordy (superseded_at = null)
const activeAmp = ampItems.filter(item => !item.json.metadata?.superseded_at);

// Kontekst z wyszukiwania semantycznego
const searchContext = searchResults
  .map(r => r.text)
  .filter(Boolean)
  .join('\n\n');

// Profil użytkownika z amfiteatru
const ampContext = activeAmp
  .map(item => {
    const cat = (item.json.metadata?.category || 'info').toUpperCase();
    return `[${cat}] ${item.json.text}`;
  })
  .join('\n\n');

const context = [
  ampContext ? `=== PROFIL UŻYTKOWNIKA ===\n${ampContext}` : '',
  searchContext ? `=== KONTEKST Z DZIENNIKA ===\n${searchContext}` : ''
].filter(Boolean).join('\n\n');

return [{ json: { context } }];
